import{_ as i,c as a,o as s,a5 as e}from"./chunks/framework.CByBVyi2.js";const b=JSON.parse('{"title":"Mac 上手指南：必备软件、终端配置与高效使用实践","description":"","frontmatter":{},"headers":[],"relativePath":"timeline/issue-86.md","filePath":"timeline/issue-86.md","lastUpdated":1775888756000}'),l={name:"timeline/issue-86.md"},t=e(`<h1 id="mac-上手指南-必备软件、终端配置与高效使用实践" tabindex="-1">Mac 上手指南：必备软件、终端配置与高效使用实践 <a class="header-anchor" href="#mac-上手指南-必备软件、终端配置与高效使用实践" aria-label="Permalink to &quot;Mac 上手指南：必备软件、终端配置与高效使用实践&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">原文地址</p><p><a href="https://github.com/jynba/jynba.github.io/issues/86" target="_blank" rel="noreferrer">Mac 上手指南：必备软件、终端配置与高效使用实践 | GitHub</a></p></div><h2 id="📖-背景" tabindex="-1">📖 背景 <a class="header-anchor" href="#📖-背景" aria-label="Permalink to &quot;📖 背景&quot;">​</a></h2><p>新入手 Mac（或从 Windows 切换）时，常见问题：</p><ul><li>不熟悉 macOS 操作逻辑</li><li>软件生态不清楚（替代工具）</li><li>终端环境不好用</li><li>缺少高效使用习惯</li></ul><p>本文整理一套从 “原始 Mac → 可高效开发环境” 的完整实践。</p><hr><h2 id="🚀-一、基础认知-与-windows-差异" tabindex="-1">🚀 一、基础认知（与 Windows 差异） <a class="header-anchor" href="#🚀-一、基础认知-与-windows-差异" aria-label="Permalink to &quot;🚀 一、基础认知（与 Windows 差异）&quot;">​</a></h2><ul><li>⌘ Command ≈ Windows Ctrl</li><li>Finder ≈ 文件管理器</li><li>.dmg 安装 = 拖入 Applications</li><li>⌘ + W 退出窗口 ⌘ + Q 退出应用</li><li>三指上滑切换应用</li><li>⌘ + 空格搜索万物</li><li>窗口设置在外层的左上角</li><li>⌘ + H 隐藏窗口；⌘ + M 最小化</li></ul><hr><h2 id="🧰-二、必备软件推荐" tabindex="-1">🧰 二、必备软件推荐 <a class="header-anchor" href="#🧰-二、必备软件推荐" aria-label="Permalink to &quot;🧰 二、必备软件推荐&quot;">​</a></h2><ul><li>Homebrew（必须；丝滑下载各种软件应用/包）</li><li>Raycast（强烈推荐，优化⌘ + 空格）</li><li>Rectangle （丝滑分屏；控制窗口位置/大小；有显示器必备）</li></ul><hr><h2 id="🛠️-三、终端环境配置-重点" tabindex="-1">🛠️ 三、终端环境配置（重点） <a class="header-anchor" href="#🛠️-三、终端环境配置-重点" aria-label="Permalink to &quot;🛠️ 三、终端环境配置（重点）&quot;">​</a></h2><p>推荐仓库： <a href="https://github.com/lewislulu/terminal-setup" target="_blank" rel="noreferrer">https://github.com/lewislulu/terminal-setup</a></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/lewislulu/terminal-setup.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> terminal-setup</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./setup.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>该脚本会自动完成：</p><ul><li>Ghostty 终端</li><li>Zsh / Fish 配置</li><li>Starship prompt</li><li>CLI 工具升级</li><li>Node (fnm)</li></ul><hr>`,19),n=[t];function r(h,o,p,c,d,u){return s(),a("div",null,n)}const k=i(l,[["render",r]]);export{b as __pageData,k as default};
